    29→ */
    30→
    31→#include "fmacros.h"
    32→
    33→#include <stdio.h>
    34→#include <string.h>
    35→#include <stdlib.h>
    36→#include <unistd.h>
    37→#include <errno.h>
    38→#include <time.h>
    39→#include <sys/time.h>
    40→#include <signal.h>
    41→#include <assert.h>
    42→#include <math.h>
    43→#include <pthread.h>
    44→
    45→#include <sds.h> /* Use hiredis sds. */
    46→#include "ae.h"
    47→#include "hiredis.h"
    48→#include "adlist.h"
    49→#include "dict.h"
    50→#include "zmalloc.h"
    51→#include "atomicvar.h"
    52→#include "crc16_slottable.h"
    53→
    54→#define UNUSED(V) ((void) V)
    55→#define RANDPTR_INITIAL_SIZE 8
    56→#define MAX_LATENCY_PRECISION 3
    57→#define MAX_THREADS 500
    58→#define CLUSTER_SLOTS 16384
    59→
    60→#define CLIENT_GET_EVENTLOOP(c) \
    61→    (c->thread_id >= 0 ? config.threads[c->thread_id]->el : config.el)
    62→
    63→struct benchmarkThread;
    64→struct clusterNode;
    65→struct redisConfig;
    66→
    67→static struct config {
    68→    aeEventLoop *el;
    69→    const char *hostip;
    70→    int hostport;
    71→    const char *hostsocket;
    72→    int numclients;
    73→    int liveclients;
    74→    int requests;
    75→    int requests_issued;
    76→    int requests_finished;
    77→    int keysize;
    78→    int datasize;
    79→    int randomkeys;
    80→    int randomkeys_keyspacelen;
    81→    int keepalive;
    82→    int pipeline;
    83→    int showerrors;
    84→    long long start;
    85→    long long totlatency;
    86→    long long *latency;
    87→    const char *title;
    88→    list *clients;
    89→    int quiet;
    90→    int csv;
    91→    int loop;
    92→    int idlemode;
    93→    int dbnum;
    94→    sds dbnumstr;
    95→    char *tests;
    96→    char *auth;
    97→    int precision;
    98→    int num_threads;
    99→    struct benchmarkThread **threads;
   100→    int cluster_mode;
   101→    int cluster_node_count;
   102→    struct clusterNode **cluster_nodes;
   103→    struct redisConfig *redis_config;
   104→    int is_fetching_slots;
   105→    int is_updating_slots;
   106→    int slots_last_update;
   107→    /* Thread mutexes to be used as fallbacks by atomicvar.h */
   108→    pthread_mutex_t requests_issued_mutex;
   109→    pthread_mutex_t requests_finished_mutex;
   110→    pthread_mutex_t liveclients_mutex;
   111→    pthread_mutex_t is_fetching_slots_mutex;
   112→    pthread_mutex_t is_updating_slots_mutex;
   113→    pthread_mutex_t updating_slots_mutex;
   114→    pthread_mutex_t slots_last_update_mutex;
   115→} config;
   116→
   117→typedef struct _client {
   118→    redisContext *context;
   119→    sds obuf;
   120→    char **randptr;         /* Pointers to :rand: strings inside the command buf */
   121→    size_t randlen;         /* Number of pointers in client->randptr */
   122→    size_t randfree;        /* Number of unused pointers in client->randptr */
   123→    char **stagptr;         /* Pointers to slot hashtags (cluster mode only) */
   124→    size_t staglen;         /* Number of pointers in client->stagptr */
   125→    size_t stagfree;        /* Number of unused pointers in client->stagptr */
   126→    size_t written;         /* Bytes of 'obuf' already written */
   127→    long long start;        /* Start time of a request */
   128→    long long latency;      /* Request latency */
   129→    int pending;            /* Number of pending requests (replies to consume) */
   130→    int prefix_pending;     /* If non-zero, number of pending prefix commands. Commands
   131→                               such as auth and select are prefixed to the pipeline of
   132→                               benchmark commands and discarded after the first send. */
   133→    int prefixlen;          /* Size in bytes of the pending prefix commands */
   134→    int thread_id;
   135→    struct clusterNode *cluster_node;
   136→    int slots_last_update;
   137→} *client;
   138→
   139→/* Threads. */
   140→
   141→typedef struct benchmarkThread {
   142→    int index;
   143→    pthread_t thread;
   144→    aeEventLoop *el;
   145→} benchmarkThread;
   146→
   147→/* Cluster. */
   148→typedef struct clusterNode {
   149→    char *ip;
   150→    int port;
   151→    sds name;
   152→    int flags;
   153→    sds replicate;  /* Master ID if node is a slave */
   154→    int *slots;
   155→    int slots_count;
   156→    int current_slot_index;
   157→    int *updated_slots;         /* Used by updateClusterSlotsConfiguration */
   158→    int updated_slots_count;    /* Used by updateClusterSlotsConfiguration */
   159→    int replicas_count;
   160→    sds *migrating; /* An array of sds where even strings are slots and odd
   161→                     * strings are the destination node IDs. */
   162→    sds *importing; /* An array of sds where even strings are slots and odd
   163→                     * strings are the source node IDs. */
   164→    int migrating_count; /* Length of the migrating array (migrating slots*2) */
   165→    int importing_count; /* Length of the importing array (importing slots*2) */
   166→    struct redisConfig *redis_config;
   167→} clusterNode;
   168→
   169→typedef struct redisConfig {
   170→    sds save;
   171→    sds appendonly;
   172→} redisConfig;
   173→
   174→/* Prototypes */
   175→static void writeHandler(aeEventLoop *el, int fd, void *privdata, int mask);
   176→static void createMissingClients(client c);
   177→static benchmarkThread *createBenchmarkThread(int index);
   178→static void freeBenchmarkThread(benchmarkThread *thread);
   179→static void freeBenchmarkThreads();
   180→static void *execBenchmarkThread(void *ptr);
   181→static clusterNode *createClusterNode(char *ip, int port);
   182→static redisConfig *getRedisConfig(const char *ip, int port,
   183→                                   const char *hostsocket);
   184→static void freeRedisConfig(redisConfig *cfg);
   185→static int fetchClusterSlotsConfiguration(client c);
   186→static void updateClusterSlotsConfiguration();
   187→int showThroughput(struct aeEventLoop *eventLoop, long long id,
   188→                   void *clientData);
   189→
   190→/* Dict callbacks */
   191→static uint64_t dictSdsHash(const void *key);
   192→static int dictSdsKeyCompare(void *privdata, const void *key1,
   193→    const void *key2);
   194→
   195→/* Implementation */
   196→static long long ustime(void) {
   197→    struct timeval tv;
   198→    long long ust;
   199→
   200→    gettimeofday(&tv, NULL);
   201→    ust = ((long)tv.tv_sec)*1000000;
   202→    ust += tv.tv_usec;
   203→    return ust;
   204→}
   205→
   206→static long long mstime(void) {
   207→    struct timeval tv;
   208→    long long mst;
   209→
   210→    gettimeofday(&tv, NULL);
